document.addEventListener('DOMContentLoaded', () => { Promise.all([
fetch('/html/_header.html').then(response => { if (!response.ok) { throw new Error('Failed to load header: ' + response.statusText); } return response.text(); }), fetch('/html/products/products_data.json').then(response => { if (!response.ok) { throw new Error('Failed to load products data: ' + response.statusText); } return response.json(); })
])
.then(([headerHtml, productsData]) => { const headerPlaceholder = document.getElementById('header-placeholder'); if (headerPlaceholder) { const parser = new DOMParser(); const doc = parser.parseFromString(headerHtml, 'text/html'); const headerContent = doc.body.innerHTML; headerPlaceholder.innerHTML = headerContent; buildProductMegaMenu(productsData); initializeHeaderFunctions(); } else { console.error("Error: Element with id 'header-placeholder' not found."); } })
.catch(error => { console.error('Error fetching data:', error); const headerPlaceholder = document.getElementById('header-placeholder'); if (headerPlaceholder) { headerPlaceholder.innerHTML = '<p>ヘッダーの読み込みに失敗しました。</p>'; } }); function buildProductMegaMenu(data) { const productDropdown = document.getElementById('product-dropdown'); if (!productDropdown) return; const mainList = productDropdown.querySelector('.dropdown-list-container .dropdown-list'); if (!mainList) return; mainList.innerHTML = ''; let dataContainer = document.getElementById('product-data-container'); if (!dataContainer) { dataContainer = document.createElement('div'); dataContainer.style.display = 'none'; dataContainer.id = 'product-data-container'; productDropdown.appendChild(dataContainer); } else { dataContainer.innerHTML = ''; } data.products_data.categories.forEach(category => { const listItem = document.createElement('li'); listItem.classList.add('has-sub-list'); listItem.setAttribute('data-category-id', category.id); const categoryLink = document.createElement('a'); categoryLink.href = category.url; categoryLink.textContent = category.name; listItem.appendChild(categoryLink); mainList.appendChild(listItem); const productGrid = document.createElement('div'); productGrid.classList.add('product-grid-view'); productGrid.id = `product-grid-${category.id}`; category.products.forEach(product => { productGrid.innerHTML += `
<a href="${product.main_page.url}" class="grid-item" data-product-id="${product.id}">
<img src="${product.image_path}" alt="${product.name}">
<p class="grid-product-title">${product.name}</p>
</a>
`; }); if (category.products.length > 0) { productGrid.innerHTML += `
<a href="${category.url}" class="grid-view-all">全ての製品を見る &gt;</a>
`; } dataContainer.appendChild(productGrid); }); } function initializeHeaderFunctions() { const mobileNav = document.querySelector('.mobile-nav'); let mobileNavOverlay = document.querySelector('.mobile-nav-overlay'); if (!mobileNavOverlay) { mobileNavOverlay = document.createElement('div'); mobileNavOverlay.classList.add('mobile-nav-overlay'); document.body.appendChild(mobileNavOverlay); } initializeMegaMenu(); initializeHeaderScroll(); const hamburgerMenu = document.querySelector('.hamburger-menu'); const overlay = document.querySelector('.mobile-nav-overlay'); if (hamburgerMenu && mobileNav && overlay) { const openMenu = () => { hamburgerMenu.classList.add('is-active'); mobileNav.classList.add('is-visible'); overlay.classList.add('is-visible'); document.body.style.overflow = 'hidden'; }; const closeMenu = () => { hamburgerMenu.classList.remove('is-active'); mobileNav.classList.remove('is-visible'); overlay.classList.remove('is-visible'); document.body.style.overflow = ''; }; hamburgerMenu.addEventListener('click', () => { if (mobileNav.classList.contains('is-visible')) { closeMenu(); } else { openMenu(); } }); overlay.addEventListener('click', closeMenu); } } function initializeMegaMenu() { const navItemsWithDropdown = document.querySelectorAll('.nav-item.has-dropdown'); let activeDropdown = null; document.addEventListener('click', (event) => { if (activeDropdown && !event.target.closest('.nav-item.has-dropdown') && !event.target.closest('.dropdown-menu')) { document.querySelectorAll('.dropdown-menu.is-visible').forEach(menu => { menu.classList.remove('is-visible'); }); document.querySelectorAll('.nav-item.is-active').forEach(item => { item.classList.remove('is-active'); }); activeDropdown = null; } }); navItemsWithDropdown.forEach(navItem => { const targetDropdown = document.getElementById(navItem.dataset.dropdownTarget); navItem.addEventListener('click', (event) => { event.preventDefault(); if (!targetDropdown) return; const isCurrentlyOpen = targetDropdown.classList.contains('is-visible'); if (activeDropdown && activeDropdown !== targetDropdown) { activeDropdown.classList.remove('is-visible'); document.querySelector(`.nav-item[data-dropdown-target="${activeDropdown.id}"]`).classList.remove('is-active'); } if (isCurrentlyOpen) { targetDropdown.classList.remove('is-visible'); navItem.classList.remove('is-active'); activeDropdown = null; } else { targetDropdown.classList.add('is-visible'); navItem.classList.add('is-active'); activeDropdown = targetDropdown; if (targetDropdown.id === 'product-dropdown') { const productDropdown = document.getElementById('product-dropdown'); const firstCategoryItem = productDropdown.querySelector('.dropdown-list li.has-sub-list'); if (firstCategoryItem) { const categoryId = firstCategoryItem.getAttribute('data-category-id'); const productGridContainer = productDropdown.querySelector('.sub-dropdown-list-container'); const productGrid = document.getElementById(`product-grid-${categoryId}`); if (!firstCategoryItem.classList.contains('is-hovered')) { productDropdown.querySelectorAll('.dropdown-list li').forEach(li => li.classList.remove('is-hovered')); firstCategoryItem.classList.add('is-hovered'); if (productGrid) { productGridContainer.innerHTML = productGrid.outerHTML; } else { productGridContainer.innerHTML = ''; } } } adjustDropdownBorderHeight(targetDropdown); } } event.stopPropagation(); }); if (targetDropdown && targetDropdown.id === 'product-dropdown') { const productCategories = targetDropdown.querySelector('.dropdown-list'); const productGridContainer = targetDropdown.querySelector('.sub-dropdown-list-container'); if (productCategories && productGridContainer) { const listItemsWithSublist = productCategories.querySelectorAll('.has-sub-list'); listItemsWithSublist.forEach(listItem => { listItem.removeEventListener('mouseenter', listItem.mouseenterHandler); const categoryLink = listItem.querySelector('a'); if (categoryLink) { categoryLink.addEventListener('click', (e) => { e.preventDefault(); e.stopPropagation(); productCategories.querySelectorAll('li').forEach(li => li.classList.remove('is-hovered')); listItem.classList.add('is-hovered'); const categoryId = listItem.getAttribute('data-category-id'); const productGrid = document.getElementById(`product-grid-${categoryId}`); if (productGrid) { productGridContainer.innerHTML = productGrid.outerHTML; } else { productGridContainer.innerHTML = ''; } adjustDropdownBorderHeight(targetDropdown); }); } }); } } }); } function adjustDropdownBorderHeight(dropdownMenu) { const leftContainer = dropdownMenu.querySelector('.dropdown-list-container'); const middleContainer = dropdownMenu.querySelector('.sub-dropdown-list-container'); if (leftContainer && middleContainer) { leftContainer.style.height = 'auto'; middleContainer.style.height = 'auto'; setTimeout(() => { const leftHeight = leftContainer.offsetHeight; const middleHeight = middleContainer.offsetHeight; const maxHeight = Math.max(leftHeight, middleHeight); leftContainer.style.minHeight = `${maxHeight}px`; middleContainer.style.minHeight = `${maxHeight}px`; }, 0); } } function initializeHeaderScroll() { const mainHeader = document.querySelector('.header'); if (!mainHeader) return; mainHeader.classList.add('is-stuck'); let lastScrollY = window.scrollY; let ticking = false; const updateHeaderState = () => { const currentScrollY = window.scrollY; const headerHeight = mainHeader.offsetHeight; const SCROLL_THRESHOLD = 50; const hideTriggerPosition = headerHeight + SCROLL_THRESHOLD; if (currentScrollY > lastScrollY && currentScrollY > hideTriggerPosition) { mainHeader.classList.add('is-hidden'); } else if (currentScrollY < lastScrollY || currentScrollY <= SCROLL_THRESHOLD) { mainHeader.classList.remove('is-hidden'); } lastScrollY = currentScrollY; ticking = false; }; const handleScroll = () => { if (!ticking) { window.requestAnimationFrame(() => { updateHeaderState(); }); ticking = true; } }; window.addEventListener('scroll', handleScroll); window.addEventListener('resize', updateHeaderState); updateHeaderState(); } const categoryTabs = document.querySelectorAll('.category-tab'); const productItems = document.querySelectorAll('.product-item'); const urlParams = new URLSearchParams(window.location.search); const initialCategory = urlParams.get('category') || 'all'; function filterProducts(category) { categoryTabs.forEach(tab => tab.classList.remove('active')); const activeTab = document.querySelector(`.category-tab[data-category="${category}"]`); if (activeTab) { activeTab.classList.add('active'); } productItems.forEach(item => { if (category === 'all' || item.classList.contains(category)) { item.style.display = 'block'; } else { item.style.display = 'none'; } }); } filterProducts(initialCategory); categoryTabs.forEach(tab => { tab.addEventListener('click', () => { const selectedCategory = tab.getAttribute('data-category'); filterProducts(selectedCategory); const newUrl = window.location.origin + window.location.pathname + `?category=${selectedCategory}`; window.history.pushState({ path: newUrl }, '', newUrl); }); }); window.addEventListener('popstate', function() { const urlParams = new URLSearchParams(window.location.search); const category = urlParams.get('category') || 'all'; filterProducts(category); }); document.querySelectorAll('.category-title').forEach(title => { title.addEventListener('click', () => { const content = title.nextElementSibling; title.classList.toggle('is-open'); content.classList.toggle('is-visible'); }); }); const mobileCategoryLinks = document.querySelectorAll('.category-items li a'); mobileCategoryLinks.forEach(link => { link.addEventListener('click', (e) => { e.preventDefault(); const selectedCategory = link.getAttribute('data-category'); filterProducts(selectedCategory); const parentContainer = link.closest('.category-list-container'); if (parentContainer) { const title = parentContainer.querySelector('.category-title'); const content = parentContainer.querySelector('.category-items'); if (title && content) { title.classList.remove('is-open'); content.classList.remove('is-visible'); } } }); }); });